	public void startBackgroundRefresh(int stalenessThreshold) {
		if (running) {
			return;
		}
		running = true;

		refresher = new Thread(() -> {
			while (running) {
				if (isLowMemory()) {
					try {
						Thread.sleep(refreshSleepMillis);
					} catch (InterruptedException e) {
						Thread.currentThread().interrupt();
						break;
					}
					continue;
				}

				if (!isRebuildAllowed()) {
					try {
						Thread.sleep(refreshSleepMillis);
					} catch (InterruptedException e) {
						Thread.currentThread().interrupt();
						break;
					}
					continue;
				}

				if (rebuildRequired.get()) {
					try {
						rebuildOnceSlow();
					} catch (Throwable t) {
						logger.error("Error while rebuilding join estimator", t);
					}
					try {
						Thread.sleep(refreshSleepMillis);
					} catch (InterruptedException e) {
						Thread.currentThread().interrupt();
						break;
					}
					continue;
				}

				if (!sketchesLoaded && lazyLoadEnabled) {
					try {
						Thread.sleep(refreshSleepMillis);
					} catch (InterruptedException e) {
						Thread.currentThread().interrupt();
						break;
					}
					continue;
				}

				boolean stale = isStale(stalenessThreshold);
				if (!stale && seenTriples > 0) {
					try {
						Thread.sleep(refreshSleepMillis);
					} catch (InterruptedException e) {
						Thread.currentThread().interrupt();
						break;
					}
					continue;
				}
//				Staleness staleness = staleness();
//				System.out.println(staleness.toString());

				try {
					rebuildOnceSlow();
				} catch (Throwable t) {
					logger.error("Error while rebuilding join estimator", t);
				}

				try {
					Thread.sleep(refreshSleepMillis);
				} catch (InterruptedException ie) {
					Thread.currentThread().interrupt();
					break;
				}

				logger.debug("RdfJoinEstimator: Rebuilt join estimator.");
			}
		}, REFRESH_THREAD_NAME);

		refresher.setDaemon(true);
		refresher.start();
	}

	public void stop() {
		running = false;
		Thread refreshThread = refresher;
		if (refreshThread != null) {
			refreshThread.interrupt();
			if (Thread.currentThread() == refreshThread) {
				return;
			}
			try {
				while (refreshThread.isAlive()) {
					refreshThread.join(250L);
				}
			} catch (InterruptedException e) {
				Thread.currentThread().interrupt();
			} finally {
				refresher = null;
			}
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Rebuild */
	/* ────────────────────────────────────────────────────────────── */

	/**
	 * Rebuild the inactive buffer from scratch (blocking). <br>
	 * Readers stay lock‑free; once complete a single volatile store publishes the fresh {@code State}.
	 *
	 * @return number of statements scanned.
	 */
	public synchronized long rebuildOnceSlow() {
		if (isLowMemory()) {
			unloadInternal(true);
			return 0L;
		}

//		try {
//			Thread.sleep(r.nextInt(10));
//		} catch (InterruptedException e) {
//			throw new RuntimeException(e);
//		}

//		long currentMemoryUsage = currentMemoryUsage();

		boolean rebuildIntoA = !usingA; // remember before toggling

		State tgt = rebuildIntoA ? bufA : bufB;
		tgt.clear(); // wipe everything (add + del)
		rebuildEpoch.incrementAndGet(); // mark rebuild in progress (odd epoch)

		long seen = 0L;
		long l = System.currentTimeMillis();
		try {
			try (SailDataset ds = sailStore.getExplicitSailSource().dataset(IsolationLevels.READ_COMMITTED);
					CloseableIteration<? extends Statement> it = ds.getStatements(null, null, null)) {

				while (it.hasNext()) {
					if (Thread.currentThread().isInterrupted() || !running && Thread.currentThread() == refresher) {
						break;
					}
					Statement st = it.next();
					try {
						synchronized (tgt) {
							ingest(tgt, st, /* isDelete= */false);
						}
					} catch (OutOfMemoryError oom) {
						logger.warn(
								"Out of memory while rebuilding estimator state; unloading sketches and deferring rebuild",
								oom);
						unloadInternal(true);
						return seen;
					} catch (Throwable e) {
						continue;
					}

					if ((seen & 0x3FFF) == 0 && isLowMemory()) {
						unloadInternal(true);
						return seen;
					}

					if (++seen % throttleEveryN == 0 && throttleMillis > 0) {
						try {
							Thread.sleep(throttleMillis);
						} catch (InterruptedException ie) {
							Thread.currentThread().interrupt();
							break;
						}
					}

					if (seen % 100000 == 0) {
						System.out.println(
								"RdfJoinEstimator: Rebuilding " + (rebuildIntoA ? "bufA" : "bufB") + ", seen "
										+ seen + " triples so far. Elapsed: " + (System.currentTimeMillis() - l) / 1000
										+ " s.");
					}
				}
			}

			current = tgt; // single volatile write → visible to all readers
			seenTriples = seen;
			approxStoreSize.set(seen);
			sketchesLoaded = true;
			rebuildRequired.set(false);
			dirty.set(true);
			usingA = !usingA;

//		long currentMemoryUsageAfter = currentMemoryUsage();
//		System.out.println("RdfJoinEstimator: Rebuilt " + (rebuildIntoA ? "bufA" : "bufB") +
//				", seen " + seen + " triples, memory usage: " +
//				currentMemoryUsageAfter / 1024 / 1024 + " MB, delta = " +
//				(currentMemoryUsageAfter - currentMemoryUsage) / 1024 / 1024 + " MB.");

			// staleness: publish times & reset churn sampler
			lastRebuildPublishMs = System.currentTimeMillis();
			churnSampler.reset();

			return seen;
		} finally {
			if ((rebuildEpoch.get() & 1L) != 0L) {
				rebuildEpoch.incrementAndGet(); // mark rebuild complete (even epoch)
			}
		}
	}

	private long currentMemoryUsage() {
		System.gc();
		try {
			Thread.sleep(10);
		} catch (InterruptedException e) {
			Thread.currentThread().interrupt();
			throw new RuntimeException(e);
		}
		System.gc();
		try {
			Thread.sleep(10);
		} catch (InterruptedException e) {
			Thread.currentThread().interrupt();
			throw new RuntimeException(e);
		}
		System.gc();
		try {
			Thread.sleep(10);
		} catch (InterruptedException e) {
			Thread.currentThread().interrupt();
			throw new RuntimeException(e);
		}

		Runtime runtime = Runtime.getRuntime();
		return runtime.totalMemory() - runtime.freeMemory();
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Incremental updates */
	/* ────────────────────────────────────────────────────────────── */

	public void addStatement(Statement st) {
		Objects.requireNonNull(st);
		if (isLowMemory()) {
			if (persistenceEnabled && persistenceFile != null) {
				persistIfDirty();
				unloadInternal(false);
			} else {
				unloadInternal(true);
			}
		}
		if (!sketchesLoaded && persistenceEnabled && persistenceFile != null && hasSnapshotAvailable(persistenceFile)) {
			tryLoadFromDisk();
		}
		if (!sketchesLoaded) {
			approxStoreSize.incrementAndGet();
			rebuildRequired.set(true);
			return;
		}

		String signature = sig(str(st.getSubject()), str(st.getPredicate()), str(st.getObject()), str(st.getContext()));
		churnSampler.recordAdd(signature, samplingInterval());
		seenTriples = approxStoreSize.incrementAndGet();

		try {
			ingestIncremental(st, false);
		} catch (OutOfMemoryError oom) {
			logger.warn("Out of memory while applying incremental estimator update; unloading sketches", oom);
			unloadInternal(true);
			return;
		}
		dirty.set(true);
	}

	public void addStatement(Resource s, IRI p, Value o, Resource c) {
		addStatement(sailStore.getValueFactory().createStatement(s, p, o, c));
	}

	public void addStatement(Resource s, IRI p, Value o) {
		addStatement(s, p, o, null);
	}

	public void deleteStatement(Statement st) {
		Objects.requireNonNull(st);
		if (isLowMemory()) {
			if (persistenceEnabled && persistenceFile != null) {
				persistIfDirty();
				unloadInternal(false);
			} else {
				unloadInternal(true);
			}
		}
		if (!sketchesLoaded && persistenceEnabled && persistenceFile != null && hasSnapshotAvailable(persistenceFile)) {
			tryLoadFromDisk();
		}
		if (!sketchesLoaded) {
			approxStoreSize.updateAndGet(v -> Math.max(0, v - 1));
			rebuildRequired.set(true);
			return;
		}

		String signature = sig(str(st.getSubject()), str(st.getPredicate()), str(st.getObject()), str(st.getContext()));
		churnSampler.recordDelete(signature, samplingInterval());
		seenTriples = approxStoreSize.updateAndGet(v -> Math.max(0, v - 1));

		try {
			ingestIncremental(st, true);
		} catch (OutOfMemoryError oom) {
			logger.warn("Out of memory while applying incremental estimator delete; unloading sketches", oom);
			unloadInternal(true);
			return;
		}
		dirty.set(true);
	}

	public void deleteStatement(Resource s, IRI p, Value o, Resource c) {
		deleteStatement(sailStore.getValueFactory().createStatement(s, p, o, c));
	}

	public void deleteStatement(Resource s, IRI p, Value o) {
		deleteStatement(s, p, o, null);
	}

	private void ingestIncremental(Statement st, boolean isDelete) {
		while (true) {
			long epoch = rebuildEpoch.get();
			if ((epoch & 1L) != 0L) {
				synchronized (bufA) {
					ingest(bufA, st, isDelete);
				}
				synchronized (bufB) {
					ingest(bufB, st, isDelete);
				}
				return;
			}

			State target = current;
			synchronized (target) {
				if (rebuildEpoch.get() != epoch) {
					continue;
				}
				ingest(target, st, isDelete);
				return;
			}
		}
	}

	/* ------------------------------------------------------------------ */

	/**
	 * Common ingestion path for both add and delete operations.
	 *
	 * @param t        target {@code State} (one of the two buffers)
	 * @param st       statement to ingest
	 * @param isDelete {@code false}=live sketch, {@code true}=tomb‑stone sketch
	 */
	private void ingest(State t, Statement st, boolean isDelete) {
		try {
			String s = str(st.getSubject());
			String p = str(st.getPredicate());
			String o = str(st.getObject());
			String c = str(st.getContext());

			int si = hash(s), pi = hash(p), oi = hash(o), ci = hash(c);
			long hs = valueFingerprint(s);
			long hp = valueFingerprint(p);
			long ho = valueFingerprint(o);
			long hc = valueFingerprint(c);
			long sig = quadFingerprint(hs, hp, ho, hc);
			long spKey = pairKey(si, pi);
			long soKey = pairKey(si, oi);
			long scKey = pairKey(si, ci);
			long poKey = pairKey(pi, oi);
			long pcKey = pairKey(pi, ci);
			long ocKey = pairKey(oi, ci);

			/* Select the correct target maps depending on add / delete. */
			var tgtST = isDelete ? t.delSingleTriples : t.singleTriples;
			var tgtS = isDelete ? t.delSingles : t.singles;
			var tgtP = isDelete ? t.delPairs : t.pairs;

			/* single‑component cardinalities (array-backed) */
			updateCell(tgtST.get(Component.S), si, sig, t.k);
			updateCell(tgtST.get(Component.P), pi, sig, t.k);
			updateCell(tgtST.get(Component.O), oi, sig, t.k);
			updateCell(tgtST.get(Component.C), ci, sig, t.k);

			/* complement sets for singles (array-backed second layer) */
			tgtS.get(Component.S).upd(Component.P, si, hp);
			tgtS.get(Component.S).upd(Component.O, si, ho);
			tgtS.get(Component.S).upd(Component.C, si, hc);

			tgtS.get(Component.P).upd(Component.S, pi, hs);
			tgtS.get(Component.P).upd(Component.O, pi, ho);
			tgtS.get(Component.P).upd(Component.C, pi, hc);

			tgtS.get(Component.O).upd(Component.S, oi, hs);
			tgtS.get(Component.O).upd(Component.P, oi, hp);
			tgtS.get(Component.O).upd(Component.C, oi, hc);

			tgtS.get(Component.C).upd(Component.S, ci, hs);
			tgtS.get(Component.C).upd(Component.P, ci, hp);
			tgtS.get(Component.C).upd(Component.O, ci, ho);

			/* pairs (triples + complements) — row-chunked arrays */
			tgtP.get(Pair.SP).upT(spKey, sig);
			tgtP.get(Pair.SP).up1(spKey, ho);
			tgtP.get(Pair.SP).up2(spKey, hc);

			tgtP.get(Pair.SO).upT(soKey, sig);
			tgtP.get(Pair.SO).up1(soKey, hp);
			tgtP.get(Pair.SO).up2(soKey, hc);

			tgtP.get(Pair.SC).upT(scKey, sig);
			tgtP.get(Pair.SC).up1(scKey, hp);
			tgtP.get(Pair.SC).up2(scKey, ho);

			tgtP.get(Pair.PO).upT(poKey, sig);
			tgtP.get(Pair.PO).up1(poKey, hs);
			tgtP.get(Pair.PO).up2(poKey, hc);

			tgtP.get(Pair.PC).upT(pcKey, sig);
			tgtP.get(Pair.PC).up1(pcKey, hs);
			tgtP.get(Pair.PC).up2(pcKey, ho);

			tgtP.get(Pair.OC).upT(ocKey, sig);
			tgtP.get(Pair.OC).up1(ocKey, hs);
			tgtP.get(Pair.OC).up2(ocKey, hp);
		} catch (NullPointerException npe) {
			// ignore NPEs from null values (e.g. missing context)
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Quick cardinalities (public) */
	/* ────────────────────────────────────────────────────────────── */

	public double cardinalitySingle(Component c, String v) {
		State snap = current;
		synchronized (snap) {
			int idx = hash(v);
			AtomicReferenceArray<UpdateSketch> arrAdd = snap.singleTriples.get(c);
			AtomicReferenceArray<UpdateSketch> arrDel = snap.delSingleTriples.get(c);
			UpdateSketch add = arrAdd.get(idx);
			UpdateSketch del = arrDel.get(idx);
			return estimateMinus(add, del);
		}
	}

	public double cardinalityPair(Pair p, String x, String y) {
		State snap = current;
		synchronized (snap) {
			long key = pairKey(hash(x), hash(y));
			UpdateSketch add = snap.pairs.get(p).getTriple(key);
			UpdateSketch del = snap.delPairs.get(p).getTriple(key);
			return estimateMinus(add, del);
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Legacy join helpers (unchanged external API) */
	/* ────────────────────────────────────────────────────────────── */

	public double estimateJoinOn(Component join, Pair a, String ax, String ay,
			Pair b, String bx, String by) {
		State snap = current;
		synchronized (snap) {
			return joinPairs(snap, join, a, ax, ay, b, bx, by);
		}
	}

	public double estimateJoinOn(Component j, Component a, String av,
			Component b, String bv) {
		State snap = current;
		synchronized (snap) {
			return joinSingles(snap, j, a, av, b, bv);
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* ✦ Fluent BGP builder ✦ */
	/* ────────────────────────────────────────────────────────────── */

	public JoinEstimate estimate(Component joinVar, String s, String p, String o, String c) {
		State snap = current;
		synchronized (snap) {
			PatternStats st = statsOf(snap, joinVar, s, p, o, c);
			Sketch bindings = st.sketch == null ? EMPTY : st.sketch;
			return new JoinEstimate(snap, joinVar, bindings, bindings.getEstimate(), st.card);
		}
	}

	public double estimateCount(Component joinVar, String s, String p, String o, String c) {
		return estimate(joinVar, s, p, o, c).estimate();
	}

	public final class JoinEstimate {
		private final State snap;
		private Component joinVar;
		private Sketch bindings;
		private double distinct;
		private double resultSize;

		private JoinEstimate(State snap, Component joinVar, Sketch bindings,
				double distinct, double size) {
			this.snap = snap;
			this.joinVar = joinVar;
			this.bindings = bindings;
			this.distinct = distinct;
			this.resultSize = size;
		}

		public JoinEstimate join(Component newJoinVar, String s, String p, String o, String c) {
			synchronized (snap) {
				/* stats of the right‑hand relation */
				PatternStats rhs = statsOf(snap, newJoinVar, s, p, o, c);

				/* intersection of bindings */
				Intersection ix = SetOperation.builder().buildIntersection();
				ix.intersect(this.bindings);
				if (rhs.sketch != null) {
					ix.intersect(rhs.sketch);
				}
				Sketch inter = ix.getResult();
				double interDistinct = inter.getEstimate();

				if (interDistinct == 0.0) { // early out
					this.bindings = inter;
					this.distinct = 0.0;
					this.resultSize = 0.0;
					this.joinVar = newJoinVar;
					return this;
				}

				/* average fan‑outs */
				double leftAvg = Math.max(0.001, distinct == 0 ? 0 : resultSize / distinct);
				double rightAvg = Math.max(0.001, rhs.distinct == 0 ? 0 : rhs.card / rhs.distinct);

				/* join‑size estimate */
				double newSize = interDistinct * leftAvg * rightAvg;

				/* round to nearest whole solution count if enabled */
				this.resultSize = roundJoinEstimate(newSize);

				/* carry forward */
				this.bindings = inter;
				this.distinct = interDistinct;
				this.joinVar = newJoinVar;
				return this;
			}
		}

		/** Estimated number of solutions produced so far. */
		public double estimate() {
			return resultSize;
		}

		public double size() {
			return resultSize;
		}

		public double count() {
			return resultSize;
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Pattern statistics */
	/* ────────────────────────────────────────────────────────────── */

	private static final class PatternStats {
		final Sketch sketch; // Θ‑sketch of join‑var bindings
		final double distinct; // = sketch.getEstimate()
		final double card; // relation size |R|

		PatternStats(Sketch s, double card) {
			this.sketch = s;
			this.distinct = s == null ? 0.0 : s.getEstimate();
			this.card = card;
		}
	}

	/** Build both |R| and Θ‑sketch for one triple pattern. */
	private PatternStats statsOf(State st, Component j,
			String s, String p, String o, String c) {

		Sketch sk = bindingsSketch(st, j, s, p, o, c);

		/* ------------- relation cardinality --------------------------- */
		EnumMap<Component, String> fixed = new EnumMap<>(Component.class);
		if (s != null) {
			fixed.put(Component.S, s);
		}
		if (p != null) {
			fixed.put(Component.P, p);
		}
		if (o != null) {
			fixed.put(Component.O, o);
		}
		if (c != null) {
			fixed.put(Component.C, c);
		}

		double card;

		switch (fixed.size()) {
		case 0:
			card = 0.0;
			break;

		case 1: {
			Map.Entry<Component, String> e = fixed.entrySet().iterator().next();
			card = cardSingle(st, e.getKey(), e.getValue());
			break;
		}

		case 2: {
			Component[] cmp = fixed.keySet().toArray(new Component[0]);
			Pair pr = findPair(cmp[0], cmp[1]);
			if (pr != null) {
				card = cardPair(st, pr, fixed.get(pr.x), fixed.get(pr.y));
			} else { // components not a known pair – conservative min
				double a = cardSingle(st, cmp[0], fixed.get(cmp[0]));
				double b = cardSingle(st, cmp[1], fixed.get(cmp[1]));
				card = Math.min(a, b);
			}
			break;
		}

		default: { // 3 or 4 bound – use smallest single cardinality
			card = Double.POSITIVE_INFINITY;
			for (Map.Entry<Component, String> e : fixed.entrySet()) {
				card = Math.min(card, cardSingle(st, e.getKey(), e.getValue()));
			}
			break;
		}
		}
		return new PatternStats(sk, card);
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Snapshot‑level cardinalities */
	/* ────────────────────────────────────────────────────────────── */

	private double cardSingle(State st, Component c, String val) {
		int idx = hash(val);
		UpdateSketch add = st.singleTriples.get(c).get(idx);
		UpdateSketch del = st.delSingleTriples.get(c).get(idx);
		return estimateMinus(add, del);
	}

	private double cardPair(State st, Pair p, String x, String y) {
		long key = pairKey(hash(x), hash(y));
		UpdateSketch add = st.pairs.get(p).getTriple(key);
		UpdateSketch del = st.delPairs.get(p).getTriple(key);
		return estimateMinus(add, del);
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Sketch helpers */
	/* ────────────────────────────────────────────────────────────── */

	private Sketch bindingsSketch(State st, Component j,
			String s, String p, String o, String c) {

		EnumMap<Component, String> f = new EnumMap<>(Component.class);
		if (s != null) {
			f.put(Component.S, s);
		}
		if (p != null) {
			f.put(Component.P, p);
		}
		if (o != null) {
			f.put(Component.O, o);
		}
		if (c != null) {
			f.put(Component.C, c);
		}

		if (f.isEmpty()) {
			return null; // no constant – unsupported
		}

		/* 1 constant → single complement */
		if (f.size() == 1) {
			Map.Entry<Component, String> e = f.entrySet().iterator().next();
			return singleWrapper(st, e.getKey()).getComplementSketch(j, hash(e.getValue()));
		}

		/* 2 constants: pair fast path */
		Component[] cs = f.keySet().toArray(new Component[0]);
		if (f.size() == 2) {
			Pair pr = findPair(cs[0], cs[1]);
			if (pr != null && (j == pr.comp1 || j == pr.comp2)) {
				int idxX = hash(f.get(pr.x));
				int idxY = hash(f.get(pr.y));
				return pairWrapper(st, pr).getComplementSketch(j, pairKey(idxX, idxY));
			}
		}

		/* generic fall‑back */
		Sketch acc = null;
		for (Map.Entry<Component, String> e : f.entrySet()) {
			Sketch sk = singleWrapper(st, e.getKey())
					.getComplementSketch(j, hash(e.getValue()));
			if (sk == null) {
				continue;
			}
			if (acc == null) {
				acc = sk;
			} else {
				Intersection ix = SetOperation.builder().buildIntersection();
				ix.intersect(acc);
				ix.intersect(sk);
				acc = ix.getResult();
			}
		}
		return acc;
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Pair & single wrappers (read‑only) */
	/* ────────────────────────────────────────────────────────────── */

	private StateSingleWrapper singleWrapper(State st, Component fixed) {
		return new StateSingleWrapper(fixed, st.singles.get(fixed), st.delSingles.get(fixed));
	}

	private StatePairWrapper pairWrapper(State st, Pair p) {
		return new StatePairWrapper(p, st.pairs.get(p), st.delPairs.get(p));
	}

	private static final class StateSingleWrapper {
		final Component fixed;
		final SingleBuild add, del;

		StateSingleWrapper(Component f, SingleBuild add, SingleBuild del) {
			this.fixed = f;
			this.add = add;
			this.del = del;
		}

		Sketch getComplementSketch(Component c, int fi) {
			if (c == fixed) {
				return null;
			}
			AtomicReferenceArray<UpdateSketch> arrA = add.cmpl.get(c);
			AtomicReferenceArray<UpdateSketch> arrD = del.cmpl.get(c);
			if (arrA == null || arrD == null) {
				return null;
			}
			UpdateSketch a = arrA.get(fi);
			UpdateSketch d = arrD.get(fi);
			return subtractSketch(a, d);
		}
	}

	private static final class StatePairWrapper {
		final Pair p;
		final PairBuild add, del;

		StatePairWrapper(Pair p, PairBuild add, PairBuild del) {
			this.p = p;
			this.add = add;
			this.del = del;
		}

		Sketch getComplementSketch(Component c, long key) {
			UpdateSketch a, d;
			if (c == p.comp1) {
				a = add.getComp1(key);
				d = del.getComp1(key);
			} else if (c == p.comp2) {
				a = add.getComp2(key);
				d = del.getComp2(key);
			} else {
				return null;
			}
			return subtractSketch(a, d);
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Join primitives */
	/* ────────────────────────────────────────────────────────────── */

	private double joinPairs(State st, Component j,
			Pair a, String ax, String ay,
			Pair b, String bx, String by) {

		long keyA = pairKey(hash(ax), hash(ay));
		long keyB = pairKey(hash(bx), hash(by));

		Sketch sa = pairWrapper(st, a).getComplementSketch(j, keyA);
		Sketch sb = pairWrapper(st, b).getComplementSketch(j, keyB);

		if (sa == null || sb == null) {
			return 0.0;
		}

		Intersection ix = SetOperation.builder().buildIntersection();
		ix.intersect(sa);
		ix.intersect(sb);
		return ix.getResult().getEstimate();
	}

	private double joinSingles(State st, Component j,
			Component a, String av,
			Component b, String bv) {

		int idxA = hash(av), idxB = hash(bv);

		Sketch sa = singleWrapper(st, a).getComplementSketch(j, idxA);
		Sketch sb = singleWrapper(st, b).getComplementSketch(j, idxB);

		if (sa == null || sb == null) {
			return 0.0;
		}

		Intersection ix = SetOperation.builder().buildIntersection();
		ix.intersect(sa);
		ix.intersect(sb);
		return ix.getResult().getEstimate();
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Unified mutable state (add + delete) */
	/* ────────────────────────────────────────────────────────────── */

	private static final class StateComponents<T> {
		public final T S;
		public final T P;
		public final T O;
		public final T C;

		StateComponents(T s, T p, T o, T c) {
			S = s;
			P = p;
			O = o;
			C = c;
		}

		T get(Component component) {
			switch (component) {
			case S:
				return S;
			case P:
				return P;
			case O:
				return O;
			case C:
				return C;
			default:
				throw new IllegalStateException("Unsupported component: " + component);
			}
		}

		void forEach(Consumer<? super T> consumer) {
			consumer.accept(S);
			consumer.accept(P);
			consumer.accept(O);
			consumer.accept(C);
		}
	}

	private static final class State {
		final int k; // sketch nominal entries
		final int buckets; // array bucket count (outer.nominalEntries)

		/* live (add) sketches */
		final StateComponents<AtomicReferenceArray<UpdateSketch>> singleTriples;
		final StateComponents<SingleBuild> singles;
		final EnumMap<Pair, PairBuild> pairs = new EnumMap<>(Pair.class);

		/* tomb‑stone (delete) sketches */
		final StateComponents<AtomicReferenceArray<UpdateSketch>> delSingleTriples;
		final StateComponents<SingleBuild> delSingles;
		final EnumMap<Pair, PairBuild> delPairs = new EnumMap<>(Pair.class);

		State(int k, int buckets) {
			this.k = k;
			this.buckets = buckets;

			singleTriples = new StateComponents<>(
					new AtomicReferenceArray<>(buckets),
					new AtomicReferenceArray<>(buckets),
					new AtomicReferenceArray<>(buckets),
					new AtomicReferenceArray<>(buckets));

			delSingleTriples = new StateComponents<>(
					new AtomicReferenceArray<>(buckets),
					new AtomicReferenceArray<>(buckets),
					new AtomicReferenceArray<>(buckets),
					new AtomicReferenceArray<>(buckets));

			singles = new StateComponents<>(
					new SingleBuild(k, Component.S, buckets),
					new SingleBuild(k, Component.P, buckets),
					new SingleBuild(k, Component.O, buckets),
					new SingleBuild(k, Component.C, buckets));

			delSingles = new StateComponents<>(
					new SingleBuild(k, Component.S, buckets),
					new SingleBuild(k, Component.P, buckets),
					new SingleBuild(k, Component.O, buckets),
					new SingleBuild(k, Component.C, buckets));

			for (Pair p : Pair.values()) {
				pairs.put(p, new PairBuild(k, buckets));
				delPairs.put(p, new PairBuild(k, buckets));
			}
		}

		void clear() {
			singleTriples.forEach(SketchBasedJoinEstimator::clearArray);
			delSingleTriples.forEach(SketchBasedJoinEstimator::clearArray);

			singles.forEach(SingleBuild::clear);
			delSingles.forEach(SingleBuild::clear);

			pairs.values().forEach(PairBuild::clear);
			delPairs.values().forEach(PairBuild::clear);
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Build‑time structures */
	/* ────────────────────────────────────────────────────────────── */

	private static final class SingleBuild {
		final int k;
		final int buckets;
		final EnumMap<Component, AtomicReferenceArray<UpdateSketch>> cmpl = new EnumMap<>(Component.class);

		SingleBuild(int k, Component fixed, int buckets) {
			this.k = k;
			this.buckets = buckets;
			for (Component c : Component.values()) {
				if (c != fixed) {
					cmpl.put(c, new AtomicReferenceArray<>(buckets));
				}
			}
		}

		void clear() {
			for (AtomicReferenceArray<UpdateSketch> arr : cmpl.values()) {
				SketchBasedJoinEstimator.clearArray(arr);
			}
		}

		void upd(Component c, int idx, long v) {
			AtomicReferenceArray<UpdateSketch> arr = cmpl.get(c);
			if (arr == null) {
				return;
			}
			UpdateSketch sk = arr.get(idx);
			if (sk == null) {
				sk = newSk(k);
				arr.set(idx, sk);
			}
			sk.update(v);
		}
	}

	private static final class PairBuild {
		final int k;
		final int buckets;

		/** Sparse rows indexed by X; each row stores only touched Y-cells. */
		final Map<Integer, Row> rows;

		PairBuild(int k, int buckets) {
			this.k = k;
			this.buckets = buckets;
			this.rows = new HashMap<>();
		}

		void clear() {
			rows.clear();
		}

		void upT(long key, long sig) {
			int x = (int) (key >>> 32);
			int y = (int) key;
			Row r = getOrCreateRow(x);
			updateSketchMap(r.triples, y, sig, k);
		}

		void up1(long key, long v) {
			int x = (int) (key >>> 32);
			int y = (int) key;
			Row r = getOrCreateRow(x);
			updateSketchMap(r.comp1, y, v, k);
		}

		void up2(long key, long v) {
			int x = (int) (key >>> 32);
			int y = (int) key;
			Row r = getOrCreateRow(x);
			updateSketchMap(r.comp2, y, v, k);
		}

		UpdateSketch getTriple(long key) {
			int x = (int) (key >>> 32);
			int y = (int) key;
			Row r = rows.get(x);
			return (r == null) ? null : r.triples.get(y);
		}

		UpdateSketch getComp1(long key) {
			int x = (int) (key >>> 32);
			int y = (int) key;
			Row r = rows.get(x);
			return (r == null) ? null : r.comp1.get(y);
		}

		UpdateSketch getComp2(long key) {
			int x = (int) (key >>> 32);
			int y = (int) key;
			Row r = rows.get(x);
			return (r == null) ? null : r.comp2.get(y);
		}

		private Row getOrCreateRow(int x) {
			Row r = rows.get(x);
			if (r == null) {
				r = new Row();
				rows.put(x, r);
			}
			return r;
		}

		static final class Row {
			final Map<Integer, UpdateSketch> triples = new HashMap<>();
			final Map<Integer, UpdateSketch> comp1 = new HashMap<>();
			final Map<Integer, UpdateSketch> comp2 = new HashMap<>();
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Utility */
	/* ────────────────────────────────────────────────────────────── */

	private static double estimateMinus(UpdateSketch add, UpdateSketch del) {
		if (add == null) {
			return 0.0;
		}
		if (del == null || del.getRetainedEntries() == 0) {
			return add.getEstimate();
		}
		AnotB diff = SetOperation.builder().buildANotB();
		diff.setA(add);
		diff.notB(del);
		return diff.getResult(false).getEstimate();
	}

	private static Sketch subtractSketch(UpdateSketch add, UpdateSketch del) {
		if (add == null) {
			return null;
		}
		if (del == null || del.getRetainedEntries() == 0) {
			return add;
		}
		AnotB diff = SetOperation.builder().buildANotB();
		diff.setA(add);
		diff.notB(del);
		return diff.getResult(false);
	}

	private static UpdateSketch newSk(int k) {
		return UpdateSketch.builder().setNominalEntries(k).build();
	}

	private int hash(String v) {
		// Ensure non-negative index in [0, nominalEntries)
		int h = Objects.hashCode(v);
		return (h & 0x7fffffff) % nominalEntries;
	}

	private static long valueFingerprint(String value) {
		long h = FNV64_OFFSET_BASIS;
		if (value != null) {
			for (int i = 0; i < value.length(); i++) {
				h ^= value.charAt(i);
				h *= FNV64_PRIME;
			}
			h ^= value.length();
		}
		return mix64(h);
	}

	private static long quadFingerprint(long s, long p, long o, long c) {
		long h = QUAD_SEED;
		h = mix64(h ^ s);
		h = mix64(h ^ p);
		h = mix64(h ^ o);
		return mix64(h ^ c);
	}

	private static long mix64(long value) {
		long z = value;
		z = (z ^ (z >>> 30)) * MIX64_C1;
		z = (z ^ (z >>> 27)) * MIX64_C2;
		return z ^ (z >>> 31);
	}

	private static long pairKey(int a, int b) {
		return (((long) a) << 32) ^ (b & 0xffffffffL);
	}

	private static Pair findPair(Component a, Component b) {
		for (Pair p : Pair.values()) {
			if ((p.x == a && p.y == b) || (p.x == b && p.y == a)) {
				return p;
			}
		}
		return null;
	}

	private String str(Resource r) {
		return r == null ? defaultContextString : r.stringValue();
	}

	private String str(Value v) {
		return v == null ? defaultContextString : v.stringValue();
	}

	private static String sig(String s, String p, String o, String c) {
		return s + ' ' + p + ' ' + o + ' ' + c;
	}

	/* ────────────────────────────────────────────────────────────── */
	/* OPTIONAL optimiser helper (unchanged API) */
	/* ────────────────────────────────────────────────────────────── */

	public double cardinality(Join node) {
		if (!isReady()) {
			return -1;
		}

		TupleExpr leftArg = node.getLeftArg();
		TupleExpr rightArg = node.getRightArg();

		return estimateJoinCardinality(leftArg, rightArg, false);
	}

	public double cardinality(LeftJoin node) {
		if (!isReady() || node.hasCondition()) {
			return -1;
		}

		TupleExpr leftArg = node.getLeftArg();
		TupleExpr rightArg = node.getRightArg();

		return estimateJoinCardinality(leftArg, rightArg, true);
	}

	public double cardinality(Filter node) {
		if (!isReady()) {
			return -1;
		}

		PatternEstimateInput input = asSketchCompatibleInput(node);
		if (input == null || !hasBoundComponent(input.pattern)) {
			return -1;
		}

		return applyFilterMultiplier(estimatePatternRows(input.pattern), input.filterMultiplier);
	}

	private double estimateJoinCardinality(TupleExpr leftArg, TupleExpr rightArg, boolean leftJoin) {
		PatternEstimateInput leftInput = asSketchCompatibleInput(leftArg);
		PatternEstimateInput rightInput = asSketchCompatibleInput(rightArg);
		if (leftInput != null && rightInput != null) {
			StatementPattern l = leftInput.pattern;
			StatementPattern r = rightInput.pattern;
			if (!hasBoundComponent(l) || !hasBoundComponent(r)) {
				return -1; // unsupported sketch case, let caller fall back
			}

			/* find first common unbound variable */
			Var common = null;
			List<Var> lVars = l.getVarList();
			for (Var v : r.getVarList()) {
				if (!v.hasValue() && lVars.contains(v)) {
					common = v;
					break;
				}
			}
			if (common == null) {
				double leftRows = applyFilterMultiplier(estimatePatternRows(l), leftInput.filterMultiplier);
				double rightRows = applyFilterMultiplier(estimatePatternRows(r), rightInput.filterMultiplier);
				double crossRows = estimateDisconnectedJoinRows(leftRows, rightRows);
				return leftJoin ? Math.max(leftRows, crossRows) : crossRows;
			}

			Component lc = getComponent(l, common);
			Component rc = getComponent(r, common);

			JoinEstimate leftEstimate = this
					.estimate(lc,
							getValueOrNull(l.getSubjectVar()),
							getValueOrNull(l.getPredicateVar()),
							getValueOrNull(l.getObjectVar()),
							getValueOrNull(l.getContextVar()));
			double leftRows = applyFilterMultiplier(leftEstimate.estimate(), leftInput.filterMultiplier);
			double joinRows = applyFilterMultiplier(leftEstimate
					.join(rc,
							getValueOrNull(r.getSubjectVar()),
							getValueOrNull(r.getPredicateVar()),
							getValueOrNull(r.getObjectVar()),
							getValueOrNull(r.getContextVar()))
					.estimate(), leftInput.filterMultiplier * rightInput.filterMultiplier);
			return leftJoin ? Math.max(leftRows, joinRows) : joinRows;
		}
		return estimateJoinCardinalityWithNestedSide(leftArg, rightArg, leftJoin);
	}

	private double estimatePatternRows(StatementPattern pattern) {
		return estimate(resolveJoinComponent(pattern),
				getValueOrNull(pattern.getSubjectVar()),
				getValueOrNull(pattern.getPredicateVar()),
				getValueOrNull(pattern.getObjectVar()),
				getValueOrNull(pattern.getContextVar()))
				.estimate();
	}

	private Component resolveJoinComponent(StatementPattern pattern) {
		if (!hasBoundValue(pattern.getSubjectVar())) {
			return Component.S;
		}
		if (!hasBoundValue(pattern.getPredicateVar())) {
			return Component.P;
		}
		if (!hasBoundValue(pattern.getObjectVar())) {
			return Component.O;
		}
		if (!hasBoundValue(pattern.getContextVar())) {
			return Component.C;
		}
		return Component.S;
	}

	private double estimateDisconnectedJoinRows(double leftRows, double rightRows) {
		double estimate = leftRows + rightRows;
		if (!Double.isFinite(estimate)) {
			return Double.MAX_VALUE;
		}
		return roundJoinEstimate(estimate);
	}

	private double roundJoinEstimate(double value) {
		if (!roundJoinEstimates || !Double.isFinite(value) || value >= Long.MAX_VALUE) {
			return value;
		}
		return Math.round(value);
	}

	private double estimateJoinCardinalityWithNestedSide(TupleExpr leftArg, TupleExpr rightArg, boolean leftJoin) {
		boolean leftNested = leftArg instanceof Join;
		boolean rightNested = rightArg instanceof Join;
		if (leftNested == rightNested) {
			return -1;
		}

		Join nested = (Join) (leftNested ? leftArg : rightArg);
		PatternEstimateInput flatInput = asSketchCompatibleInput(leftNested ? rightArg : leftArg);
		if (flatInput == null || !hasBoundComponent(flatInput.pattern)) {
			return -1;
		}
		StatementPattern flat = flatInput.pattern;

		java.util.Set<String> nestedBindingNames = nested.getBindingNames();
		for (Var var : flat.getVarList()) {
			if (var == null || var.hasValue() || var.getName() == null || !nestedBindingNames.contains(var.getName())) {
				continue;
			}

			TupleSketchStats nestedStats = estimateTupleExprForJoinVar(nested, var.getName());
			if (nestedStats == null) {
				continue;
			}

			TupleSketchStats flatStats = estimatePatternForJoinVar(flat, var.getName(), flatInput.filterMultiplier);
			if (flatStats == null) {
				continue;
			}

			double leftRows = leftNested ? nestedStats.rows : flatStats.rows;
			double joinRows = mergeTupleSketchStats(leftNested ? nestedStats : flatStats,
					leftNested ? flatStats : nestedStats).rows;
			return leftJoin ? Math.max(leftRows, joinRows) : joinRows;
		}

		double nestedRows = estimateTupleExprRows(nested);
		if (nestedRows < 0.0) {
			return -1;
		}
		double flatRows = applyFilterMultiplier(estimatePatternRows(flat), flatInput.filterMultiplier);
		double crossRows = estimateDisconnectedJoinRows(leftNested ? nestedRows : flatRows,
				leftNested ? flatRows : nestedRows);
		if (leftJoin) {
			double leftRows = leftNested ? nestedRows : flatRows;
			return Math.max(leftRows, crossRows);
		}
		return crossRows;
	}

	private double estimateTupleExprRows(TupleExpr tupleExpr) {
		PatternEstimateInput patternInput = asSketchCompatibleInput(tupleExpr);
		if (patternInput != null) {
			return hasBoundComponent(patternInput.pattern)
					? applyFilterMultiplier(estimatePatternRows(patternInput.pattern), patternInput.filterMultiplier)
					: -1;
		}

		if (tupleExpr instanceof Join) {
			Join join = (Join) tupleExpr;
			return estimateJoinCardinality(join.getLeftArg(), join.getRightArg(), false);
		}

		if (tupleExpr instanceof LeftJoin) {
			LeftJoin join = (LeftJoin) tupleExpr;
			if (join.hasCondition()) {
				return -1;
			}
			return estimateJoinCardinality(join.getLeftArg(), join.getRightArg(), true);
		}

		return -1;
	}

	private TupleSketchStats estimateTupleExprForJoinVar(TupleExpr tupleExpr, String joinVarName) {
		PatternEstimateInput patternInput = asSketchCompatibleInput(tupleExpr);
		if (patternInput != null) {
			return estimatePatternForJoinVar(patternInput.pattern, joinVarName, patternInput.filterMultiplier);
		}

		if (tupleExpr instanceof Join) {
			Join join = (Join) tupleExpr;
			TupleSketchStats leftStats = estimateTupleExprForJoinVar(join.getLeftArg(), joinVarName);
			TupleSketchStats rightStats = estimateTupleExprForJoinVar(join.getRightArg(), joinVarName);
			if (leftStats == null || rightStats == null) {
				return null;
			}
			return mergeTupleSketchStats(leftStats, rightStats);
		}

		return null;
	}

	private TupleSketchStats estimatePatternForJoinVar(StatementPattern pattern, String joinVarName,
			double filterMultiplier) {
		if (!hasBoundComponent(pattern)) {
			return null;
		}

		Var joinVar = findUnboundVarByName(pattern, joinVarName);
		if (joinVar == null) {
			return null;
		}

		JoinEstimate estimate = estimate(getComponent(pattern, joinVar),
				getValueOrNull(pattern.getSubjectVar()),
				getValueOrNull(pattern.getPredicateVar()),
				getValueOrNull(pattern.getObjectVar()),
				getValueOrNull(pattern.getContextVar()));
		return new TupleSketchStats(estimate.bindings, estimate.distinct,
				applyFilterMultiplier(estimate.resultSize, filterMultiplier));
	}

	private TupleSketchStats mergeTupleSketchStats(TupleSketchStats leftStats, TupleSketchStats rightStats) {
		Intersection ix = SetOperation.builder().buildIntersection();
		ix.intersect(leftStats.bindings);
		ix.intersect(rightStats.bindings);
		Sketch inter = ix.getResult();
		double interDistinct = inter.getEstimate();

		if (interDistinct == 0.0) {
			return new TupleSketchStats(inter, 0.0, 0.0);
		}

		double leftAvg = Math.max(0.001, leftStats.distinct == 0 ? 0 : leftStats.rows / leftStats.distinct);
		double rightAvg = Math.max(0.001, rightStats.distinct == 0 ? 0 : rightStats.rows / rightStats.distinct);
		double joinRows = roundJoinEstimate(interDistinct * leftAvg * rightAvg);
		return new TupleSketchStats(inter, interDistinct, joinRows);
	}

	private Var findUnboundVarByName(StatementPattern pattern, String varName) {
		for (Var var : pattern.getVarList()) {
			if (var != null && !var.hasValue() && varName.equals(var.getName())) {
				return var;
			}
		}
		return null;
	}

	private static final class TupleSketchStats {
		private final Sketch bindings;
		private final double distinct;
		private final double rows;

		private TupleSketchStats(Sketch bindings, double distinct, double rows) {
			this.bindings = bindings;
			this.distinct = distinct;
			this.rows = rows;
		}
	}

	private static final class PatternEstimateInput {
		private final StatementPattern pattern;
		private final double filterMultiplier;

		private PatternEstimateInput(StatementPattern pattern, double filterMultiplier) {
			this.pattern = pattern;
			this.filterMultiplier = filterMultiplier;
		}
	}

	private PatternEstimateInput asSketchCompatibleInput(TupleExpr tupleExpr) {
		if (tupleExpr instanceof StatementPattern) {
			return new PatternEstimateInput((StatementPattern) tupleExpr, 1.0d);
		}
		if (tupleExpr instanceof Filter) {
			return asSketchCompatibleInput((Filter) tupleExpr);
		}
		return null;
	}

	private PatternEstimateInput asSketchCompatibleInput(Filter filter) {
		PatternEstimateInput input = asSketchCompatibleInput(filter.getArg());
		if (input == null) {
			return null;
		}
		double filterMultiplier = resolveFilterMultiplier(filter, input.pattern);
		double combinedMultiplier = normalizeFilterMultiplier(input.filterMultiplier * filterMultiplier);
		return new PatternEstimateInput(input.pattern, combinedMultiplier);
	}

	private double resolveFilterMultiplier(Filter filter, StatementPattern pattern) {
		if (!FilterSelectivityKeys.conditionIntersectsPattern(filter.getCondition(), pattern)) {
			return 1.0d;
		}
		double learnedMultiplier = resolveLearnedFilterMultiplier(filter, pattern);
		if (learnedMultiplier > 0.0d) {
			return learnedMultiplier;
		}
		double heuristicMultiplier = estimateHeuristicFilterMultiplier(filter, pattern);
		if (heuristicMultiplier > 0.0d) {
			return heuristicMultiplier;
		}
		return 1.0d;
	}

	private double resolveLearnedFilterMultiplier(Filter filter, StatementPattern pattern) {
		JoinStatsProvider statsProvider = learnedStatsProvider;
		if (statsProvider == null || filter.getCondition() == null) {
			return -1.0d;
		}
		PatternKey patternKey = FilterSelectivityKeys.patternKeyFor(pattern);
		if (patternKey == null || !statsProvider.hasStats(patternKey)) {
			return -1.0d;
		}
		String filterKey = FilterSelectivityKeys.filterKeyFor(filter.getCondition());
		double ratio = statsProvider.getFilterPassRatio(patternKey, filterKey);
		if (isValidFilterMultiplier(ratio)) {
			return normalizeFilterMultiplier(ratio);
		}
		ratio = statsProvider.getPatternPassRatio(patternKey);
		if (isValidFilterMultiplier(ratio)) {
			return normalizeFilterMultiplier(ratio);
		}
		return -1.0d;
	}

	private double estimateHeuristicFilterMultiplier(Filter filter, StatementPattern pattern) {
		if (filter.getCondition() == null) {
			return -1.0d;
		}
		double baseRows = estimatePatternRows(pattern);
		if (!(baseRows > 0.0d) || !Double.isFinite(baseRows)) {
			return -1.0d;
		}
		StatementPattern narrowedPattern = pattern.clone();
		if (!bindSimpleFilterCondition(narrowedPattern, filter.getCondition())) {
			return -1.0d;
		}
		double narrowedRows = estimatePatternRows(narrowedPattern);
		if (narrowedRows < 0.0d || !Double.isFinite(narrowedRows)) {
			return -1.0d;
		}
		double ratio = narrowedRows / baseRows;
		if (!Double.isFinite(ratio) || ratio < 0.0d) {
			return -1.0d;
		}
		return normalizeFilterMultiplier(ratio);
	}

	private boolean isValidFilterMultiplier(double value) {
		return Double.isFinite(value) && value > 0.0d && value <= 1.0d;
	}

	private double normalizeFilterMultiplier(double value) {
		if (!Double.isFinite(value) || value <= 0.0d) {
			return 1.0d;
		}
		return Math.max(MIN_FILTER_MULTIPLIER, Math.min(1.0d, value));
	}

	private double applyFilterMultiplier(double rows, double multiplier) {
		if (!Double.isFinite(rows)) {
			return rows;
		}
		if (!(multiplier > 0.0d) || multiplier >= 1.0d) {
			return rows;
		}
		return rows * normalizeFilterMultiplier(multiplier);
	}

	private boolean bindSimpleFilterCondition(StatementPattern pattern, ValueExpr condition) {
		if (condition instanceof And) {
			And and = (And) condition;
			return bindSimpleFilterCondition(pattern, and.getLeftArg())
					&& bindSimpleFilterCondition(pattern, and.getRightArg());
		}

		if (condition instanceof Compare) {
			Compare compare = (Compare) condition;
			if (compare.getOperator() != Compare.CompareOp.EQ) {
				return false;
			}

			return bindVarToConstant(pattern, compare.getLeftArg(), compare.getRightArg())
					|| bindVarToConstant(pattern, compare.getRightArg(), compare.getLeftArg());
		}

		if (condition instanceof SameTerm) {
			SameTerm sameTerm = (SameTerm) condition;
			return bindVarToConstant(pattern, sameTerm.getLeftArg(), sameTerm.getRightArg())
					|| bindVarToConstant(pattern, sameTerm.getRightArg(), sameTerm.getLeftArg());
		}

		return false;
	}

	private boolean bindVarToConstant(StatementPattern pattern, ValueExpr maybeVarExpr, ValueExpr maybeValueExpr) {
		if (!(maybeVarExpr instanceof Var) || !(maybeValueExpr instanceof ValueConstant)) {
			return false;
		}

		Var filterVar = (Var) maybeVarExpr;
		ValueConstant constant = (ValueConstant) maybeValueExpr;
		if (filterVar.getName() == null || constant.getValue() == null) {
			return false;
		}

		return bindPatternVars(pattern, filterVar.getName(), constant.getValue());
	}

	private boolean bindPatternVars(StatementPattern pattern, String varName, Value value) {
		boolean found = false;
		for (Var patternVar : new Var[] {
				pattern.getSubjectVar(),
				pattern.getPredicateVar(),
				pattern.getObjectVar(),
				pattern.getContextVar() }) {
			if (patternVar == null || !varName.equals(patternVar.getName())) {
				continue;
			}

			found = true;
			if (patternVar.hasValue() && !Objects.equals(patternVar.getValue(), value)) {
				return false;
			}
			if (!patternVar.hasValue()) {
				pattern.replaceChildNode(patternVar,
						Var.of(patternVar.getName(), value, patternVar.isAnonymous(), patternVar.isConstant()));
			}
		}
		return found;
	}

	private String getValueOrNull(Var v) {
		return (v == null || v.getValue() == null)
				? null
				: v.getValue().stringValue();
	}

	private boolean hasBoundComponent(StatementPattern sp) {
		return hasBoundValue(sp.getSubjectVar())
				|| hasBoundValue(sp.getPredicateVar())
				|| hasBoundValue(sp.getObjectVar())
				|| hasBoundValue(sp.getContextVar());
	}

	private boolean hasBoundValue(Var var) {
		return var != null && var.hasValue();
	}

	private Component getComponent(StatementPattern sp, Var var) {
		if (var.equals(sp.getSubjectVar())) {
			return Component.S;
		}
		if (var.equals(sp.getPredicateVar())) {
			return Component.P;
		}
		if (var.equals(sp.getObjectVar())) {
			return Component.O;
		}
		if (var.equals(sp.getContextVar())) {
			return Component.C;
		}
		throw new IllegalStateException("Unexpected variable " + var + " in pattern " + sp);
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Staleness API */
	/* ────────────────────────────────────────────────────────────── */

	private static final class ChurnSnapshot {
		final int sampled;
		final int removed;
		final int readded;

		ChurnSnapshot(int sampled, int removed, int readded) {
			this.sampled = sampled;
			this.removed = removed;
			this.readded = readded;
		}

		double removalRatio() {
			return sampled == 0 ? 0.0 : (double) removed / (double) sampled;
		}

		double readdRatio() {
			return sampled == 0 ? 0.0 : (double) readded / (double) sampled;
		}
	}

	private static final class ChurnSampler {
		private enum State {
			ADDED,
			DELETED_AFTER_ADD,
			READDED_AFTER_DELETE
		}

		private final ConcurrentHashMap<String, State> samples = new ConcurrentHashMap<>();
		private long eventsSinceLastSample = 0L;

		void reset() {
			samples.clear();
			eventsSinceLastSample = 0L;
		}

		void recordAdd(String signature, long sampleEvery) {
			record(signature, sampleEvery, true);
		}

		void recordDelete(String signature, long sampleEvery) {
			record(signature, sampleEvery, false);
		}

		private void record(String signature, long sampleEvery, boolean isAdd) {
			if (sampleEvery <= 0) {
				return;
			}
			eventsSinceLastSample++;
			if (eventsSinceLastSample < sampleEvery) {
				return;
			}
			eventsSinceLastSample = 0L;

			samples.compute(signature, (sig, state) -> {
				if (state == null) {
					return isAdd ? State.ADDED : null;
				}
				if (isAdd && state == State.DELETED_AFTER_ADD) {
					return State.READDED_AFTER_DELETE;
				}
				if (!isAdd && state == State.ADDED) {
					return State.DELETED_AFTER_ADD;
				}
				return state;
			});
		}

		ChurnSnapshot snapshot() {
			int sampled = 0;
			int removed = 0;
			int readded = 0;
			for (State state : samples.values()) {
				sampled++;
				if (state == State.DELETED_AFTER_ADD || state == State.READDED_AFTER_DELETE) {
					removed++;
				}
				if (state == State.READDED_AFTER_DELETE) {
					readded++;
				}
			}
			return new ChurnSnapshot(sampled, removed, readded);
		}
	}

	/**
	 * Immutable staleness snapshot. All values are approximate by design.
	 */
	public static final class Staleness {
		public final long ageMillis; // AoI: time since last publish
		public final long lastRebuildPublishMs;

		// churn-specific
		public final int sampledAdds;
		public final int sampledRemoved;
		public final int sampledReadded;
		public final double sampledRemovalRatio;
		public final double sampledReaddRatio;

		public final double stalenessScore; // combined 0..1+

		private Staleness(
				long ageMillis,
				long lastRebuildPublishMs,
				int sampledAdds,
				int sampledRemoved,
				int sampledReadded,
				double sampledRemovalRatio,
				double sampledReaddRatio,
				double stalenessScore) {
			this.ageMillis = ageMillis;
			this.lastRebuildPublishMs = lastRebuildPublishMs;
			this.sampledAdds = sampledAdds;
			this.sampledRemoved = sampledRemoved;
			this.sampledReadded = sampledReadded;
			this.sampledRemovalRatio = sampledRemovalRatio;
			this.sampledReaddRatio = sampledReaddRatio;
			this.stalenessScore = stalenessScore;
		}

		@Override
		public String toString() {
			return "Staleness{" +
					"ageMillis=" + ageMillis +
					", lastRebuildPublishMs=" + lastRebuildPublishMs +
					", sampledAdds=" + sampledAdds +
					", sampledRemoved=" + sampledRemoved +
					", sampledReadded=" + sampledReadded +
					", sampledRemovalRatio=" + sampledRemovalRatio +
					", sampledReaddRatio=" + sampledReaddRatio +
					", stalenessScore=" + stalenessScore +
					'}';
		}
	}

	/**
	 * Compute a staleness snapshot using the *current* published State. No locks taken.
	 *
	 * This is O(total number of populated sketch keys) and intended for occasional diagnostics or adaptive scheduling.
	 * All numbers are approximate by design of Theta sketches.
	 */
	public Staleness staleness() {
		final long now = System.currentTimeMillis();
		final long age = lastRebuildPublishMs == 0L ? Long.MAX_VALUE : (now - lastRebuildPublishMs);

		final int decisionMin = 1;

		ChurnSnapshot churnSnapshot = churnSampler.snapshot();
		double churnRatio = churnSnapshot.sampled < decisionMin
				? 0.0
				: Math.max(churnSnapshot.readdRatio(), churnSnapshot.removalRatio());

		double score = clamp(churnRatio, 0.0, 1.0);

		return new Staleness(
				age,
				lastRebuildPublishMs,
				churnSnapshot.sampled,
				churnSnapshot.removed,
				churnSnapshot.readded,
				churnSnapshot.removalRatio(),
				churnSnapshot.readdRatio(),
				score);
	}

	/** Convenience: true if combined staleness score exceeds a given threshold. */
	public boolean isStale(double threshold) {
		Staleness staleness = staleness();
		int decisionMin = 1;
		boolean removalBreach = staleness.sampledAdds >= decisionMin
				&& staleness.sampledRemovalRatio >= churnRemovalRatioThreshold;
		boolean readdBreach = staleness.sampledAdds >= decisionMin
				&& staleness.sampledReaddRatio >= churnReaddThreshold;
		return removalBreach || readdBreach || staleness.stalenessScore > threshold;
	}

	// ──────────────────────────────────────────────────────────────
	// Staleness helpers (private)
	// ──────────────────────────────────────────────────────────────

	private static double clamp(double v, double lo, double hi) {
		return Math.max(lo, Math.min(hi, v));
	}

	/**
	 * Determine how frequently churn events should be sampled, expressed as "every N statements".
	 * <p>
	 * Rules:
	 * <ul>
	 * <li>When both {@code churnSamplePercent} and {@code churnSampleMin} are zero or negative, sampling is
	 * disabled.</li>
	 * <li>Base interval is derived from {@code churnSamplePercent * approxStoreSize} (rounded to ≥ 1) when percent &gt;
	 * 0.</li>
	 * <li>The interval is never smaller (more frequent) than {@code churnSampleMin} when
	 * {@code churnSampleMin &gt; 0}.</li>
	 * <li>If {@code churnSampleMax &gt; 0} and the calculated interval is below it, the interval is raised to
	 * {@code churnSampleMax} to avoid oversampling.</li>
	 * </ul>
	 */
	private long samplingInterval() {
		if (churnSamplePercent <= 0.0 && churnSampleMin <= 0) {
			return 0L; // sampling disabled
		}

		long interval = 0L;

		if (churnSamplePercent > 0.0) {
			double raw = approxStoreSize.get() * churnSamplePercent;
			long pctInterval = Math.max(1L, Math.round(raw));
			interval = Math.max(interval, pctInterval);
		}

		if (churnSampleMin > 0) {
			interval = Math.max(interval, churnSampleMin);
		}

		if (churnSampleMax > 0 && interval > 0 && interval < churnSampleMax) {
			interval = churnSampleMax;
		}

		return interval;
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Persistence public API */
	/* ────────────────────────────────────────────────────────────── */

	/**
	 * Best-effort snapshot persistence intended for scheduled store-level sync/commit paths.
	 *
	 * @return true if a snapshot was written.
	 */
	public boolean persistIfDirty() {
		if (!persistenceEnabled || persistenceFile == null) {
			return false;
		}
		if (!dirty.get() || !sketchesLoaded) {
			return false;
		}
		synchronized (persistLock) {
			if (!dirty.get() || !sketchesLoaded) {
				return false;
			}
			try {
				writeSnapshot(persistenceFile);
				dirty.set(false);
				return true;
			} catch (Throwable t) {
				logger.warn("Failed to persist join estimator snapshot to {}", persistenceFile, t);
				return false;
			}
		}
	}

	/**
	 * Release in-memory sketches. Query planning falls back until sketches are lazy-loaded or rebuilt.
	 */
	public void unload() {
		unloadInternal(false);
	}

	private void unloadInternal(boolean markRebuildRequired) {
		synchronized (bufA) {
			bufA.clear();
		}
		synchronized (bufB) {
			bufB.clear();
		}
		seenTriples = 0L;
		sketchesLoaded = false;
		if (markRebuildRequired) {
			rebuildRequired.set(true);
		}
	}

	private boolean tryLoadFromDisk() {
		if (!persistenceEnabled || persistenceFile == null) {
			return false;
		}
		if (isLowMemory()) {
			return false;
		}
		synchronized (loadLock) {
			if (sketchesLoaded) {
				return true;
			}
			if (!hasSnapshotAvailable(persistenceFile)) {
				return false;
			}
			try {
				readSnapshot(persistenceFile);
				sketchesLoaded = true;
				rebuildRequired.set(false);
				dirty.set(false);
				return true;
			} catch (Throwable t) {
				logger.warn("Failed to load join estimator snapshot from {}", persistenceFile, t);
				return false;
			}
		}
	}

	private static boolean hasSnapshotAvailable(Path file) {
		if (file == null) {
			return false;
		}
		cleanupClearedSnapshotCacheEntries();
		if (Files.isReadable(file)) {
			return true;
		}
		Path key = normalizeSnapshotKey(file);
		SnapshotCacheEntry cached = SNAPSHOT_CACHE.get(key);
		if (cached == null) {
			return false;
		}
		if (cached.payload() != null) {
			return true;
		}
		SNAPSHOT_CACHE.remove(key, cached);
		return false;
	}

	private static Path normalizeSnapshotKey(Path file) {
		return file.toAbsolutePath().normalize();
	}

	private boolean isLowMemory() {
		BooleanSupplier supplier = lowMemorySupplier;
		if (supplier != null) {
			try {
				return supplier.getAsBoolean();
			} catch (Throwable t) {
				logger.debug("Ignoring low-memory supplier failure", t);
			}
		}
		return isMemoryLowHeuristic();
	}

	private boolean isRebuildAllowed() {
		BooleanSupplier supplier = rebuildAllowedSupplier;
		if (supplier != null) {
			try {
				return supplier.getAsBoolean();
			} catch (Throwable t) {
				logger.debug("Ignoring rebuild-allowed supplier failure", t);
			}
		}
		return true;
	}

	private static boolean isMemoryLowHeuristic() {
		Runtime rt = Runtime.getRuntime();
		long max = rt.maxMemory();
		long total = rt.totalMemory();
		long free = rt.freeMemory();
		long used = total - free;
		long freeToAllocate = max - used;

		final long absMin = 64L * 1024L * 1024L;
		final double ratioMin = 1.0 / 8.0;
		return freeToAllocate < absMin || (freeToAllocate + 0.0) / (max + 0.0) < ratioMin;
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Snapshot IO */
	/* ────────────────────────────────────────────────────────────── */

	private void writeSnapshot(Path file) throws IOException {
		State snap = current;
		synchronized (snap) {
			Path parent = file.getParent();
			if (parent != null) {
				Files.createDirectories(parent);
			}

			Path tmp = file.resolveSibling(file.getFileName().toString() + ".tmp");
			try (OutputStream raw = new BufferedOutputStream(
					Files.newOutputStream(tmp, StandardOpenOption.CREATE, StandardOpenOption.TRUNCATE_EXISTING))) {
				raw.write(PERSIST_MAGIC);
				raw.write(PERSIST_VERSION);
				raw.flush();

				try (DataOutputStream out = new DataOutputStream(new GZIPOutputStream(raw))) {
					out.writeInt(snap.buckets);
					out.writeInt(snap.k);
					writeString(out, defaultContextString);
					out.writeLong(seenTriples);
					out.writeLong(approxStoreSize.get());
					out.writeLong(lastRebuildPublishMs);
					writeState(out, snap);
					out.writeByte(REC_EOF);
				}
			}

			try {
				Files.move(tmp, file, StandardCopyOption.REPLACE_EXISTING, StandardCopyOption.ATOMIC_MOVE);
			} catch (IOException e) {
				Files.move(tmp, file, StandardCopyOption.REPLACE_EXISTING);
			}
			SNAPSHOT_CACHE.remove(normalizeSnapshotKey(file));
		}
	}

	private void readSnapshot(Path file) throws IOException {
		byte[] payload = loadSnapshotPayload(file);
		try (DataInputStream in = new DataInputStream(new ByteArrayInputStream(payload))) {
			int buckets = in.readInt();
			int k = in.readInt();
			String defCtx = readString(in);
			long seen = in.readLong();
			long approx = in.readLong();
			long lastPublish = in.readLong();

			if (buckets != this.nominalEntries) {
				throw new IOException(
						"Snapshot buckets mismatch: snapshot=" + buckets + " current=" + this.nominalEntries);
			}
			if (k != this.bufA.k) {
				throw new IOException("Snapshot sketchK mismatch: snapshot=" + k + " current=" + this.bufA.k);
			}
			if (!Objects.equals(defCtx, this.defaultContextString)) {
				throw new IOException("Snapshot defaultContextString mismatch");
			}

			synchronized (bufA) {
				bufA.clear();
				synchronized (bufB) {
					bufB.clear();
					readStateInto(in, bufA, bufB);
				}
			}

			current = bufA;
			usingA = true;
			seenTriples = seen;
			approxStoreSize.set(approx);
			lastRebuildPublishMs = lastPublish;
			churnSampler.reset();
		}
	}

	private static byte[] loadSnapshotPayload(Path file) throws IOException {
		cleanupClearedSnapshotCacheEntries();
		Path key = normalizeSnapshotKey(file);
		SnapshotCacheEntry cached = SNAPSHOT_CACHE.get(key);
		if (cached != null) {
			byte[] cachedPayload = cached.payload();
			if (cachedPayload == null) {
				SNAPSHOT_CACHE.remove(key, cached);
			} else if (!Files.isReadable(file)) {
				return cachedPayload;
			} else {
				long modifiedMillis = Files.getLastModifiedTime(file).toMillis();
				long size = Files.size(file);
				if (cached.matches(size, modifiedMillis)) {
					return cachedPayload;
				}
			}
		}

		if (!Files.isReadable(file)) {
			throw new IOException("Snapshot file is not readable and no cached payload exists: " + file);
		}

		byte[] raw = Files.readAllBytes(file);
		long modifiedMillis = Files.getLastModifiedTime(file).toMillis();
		validateSnapshotHeader(raw);
		byte[] payload = inflateSnapshotPayload(raw);
		SNAPSHOT_CACHE.put(key, new SnapshotCacheEntry(raw.length, modifiedMillis, payload));
		return payload;
	}

	private static void cleanupClearedSnapshotCacheEntries() {
		SNAPSHOT_CACHE.entrySet().removeIf(entry -> entry.getValue().payload() == null);
	}

	private static void validateSnapshotHeader(byte[] raw) throws IOException {
		int headerLen = PERSIST_MAGIC.length + 1;
		if (raw.length < headerLen) {
			throw new EOFException("Short read of estimator snapshot header");
		}
		for (int i = 0; i < PERSIST_MAGIC.length; i++) {
			if (raw[i] != PERSIST_MAGIC[i]) {
				throw new IOException("Not a join estimator snapshot file");
			}
		}
		int version = raw[PERSIST_MAGIC.length] & 0xFF;
		if (version != PERSIST_VERSION) {
			throw new IOException("Unsupported join estimator snapshot version: " + version);
		}
	}

	private static byte[] inflateSnapshotPayload(byte[] raw) throws IOException {
		int offset = PERSIST_MAGIC.length + 1;
		try (GZIPInputStream gzip = new GZIPInputStream(new ByteArrayInputStream(raw, offset, raw.length - offset));
				ByteArrayOutputStream out = new ByteArrayOutputStream(Math.max(1024, raw.length))) {
			byte[] buffer = new byte[8192];
			int read;
			while ((read = gzip.read(buffer)) != -1) {
				out.write(buffer, 0, read);
			}
			return out.toByteArray();
		}
	}

	private static void writeString(DataOutputStream out, String value) throws IOException {
		byte[] bytes = value.getBytes(StandardCharsets.UTF_8);
		out.writeInt(bytes.length);
		out.write(bytes);
	}

	private static String readString(DataInputStream in) throws IOException {
		int len = in.readInt();
		if (len < 0 || len > MAX_STRING_BYTES) {
			throw new IOException("Invalid string length: " + len);
		}
		byte[] bytes = new byte[len];
		in.readFully(bytes);
		return new String(bytes, StandardCharsets.UTF_8);
	}

	private static void writeSketch(DataOutputStream out, UpdateSketch sketch) throws IOException {
		int retained = sketch.getRetainedEntries();
		out.writeInt(retained);
		HashIterator it = sketch.iterator();
		int written = 0;
		while (it.next()) {
			out.writeLong(it.get());
			written++;
		}
		if (written != retained) {
			throw new IOException("Sketch retained-entry count changed while serializing");
		}
	}

	private static UpdateSketch readSketch(DataInputStream in, int k) throws IOException {
		int retained = in.readInt();
		if (retained < 0 || retained > MAX_SKETCH_ENTRIES) {
			throw new IOException("Invalid retained entry count: " + retained);
		}
		UpdateSketch sketch = newSk(k);
		for (int i = 0; i < retained; i++) {
			sketch.update(in.readLong());
		}
		return sketch;
	}

	private static UpdateSketch cloneSketch(UpdateSketch source, int k) {
		UpdateSketch copy = newSk(k);
		HashIterator it = source.iterator();
		while (it.next()) {
			copy.update(it.get());
		}
		return copy;
	}

	private static void writeState(DataOutputStream out, State state) throws IOException {
		for (Component c : Component.values()) {
			writeSketchArray(out, REC_SINGLE_TRIPLE, false, (byte) c.ordinal(), state.singleTriples.get(c));
			writeSketchArray(out, REC_SINGLE_TRIPLE, true, (byte) c.ordinal(), state.delSingleTriples.get(c));
		}

		for (Component fixed : Component.values()) {
			SingleBuild add = state.singles.get(fixed);
			SingleBuild del = state.delSingles.get(fixed);
			for (Map.Entry<Component, AtomicReferenceArray<UpdateSketch>> entry : add.cmpl.entrySet()) {
				writeSketchArray(out, REC_SINGLE_CPL, false, (byte) fixed.ordinal(), (byte) entry.getKey().ordinal(),
						entry.getValue());
			}
			for (Map.Entry<Component, AtomicReferenceArray<UpdateSketch>> entry : del.cmpl.entrySet()) {
				writeSketchArray(out, REC_SINGLE_CPL, true, (byte) fixed.ordinal(), (byte) entry.getKey().ordinal(),
						entry.getValue());
			}
		}

		for (Pair pair : Pair.values()) {
			writePairBuild(out, pair, false, state.pairs.get(pair));
			writePairBuild(out, pair, true, state.delPairs.get(pair));
		}
	}

	private static void writeSketchArray(DataOutputStream out, byte recType, boolean isDelete, byte comp,
			AtomicReferenceArray<UpdateSketch> array) throws IOException {
		if (array == null) {
			return;
		}
		for (int i = 0; i < array.length(); i++) {
			UpdateSketch sketch = array.get(i);
			if (sketch == null || sketch.getRetainedEntries() == 0) {
				continue;
			}
			out.writeByte(recType);
			out.writeBoolean(isDelete);
			out.writeByte(comp);
			out.writeInt(i);
			writeSketch(out, sketch);
		}
	}

	private static void writeSketchArray(DataOutputStream out, byte recType, boolean isDelete, byte fixed, byte other,
			AtomicReferenceArray<UpdateSketch> array) throws IOException {
		if (array == null) {
			return;
		}
		for (int i = 0; i < array.length(); i++) {
			UpdateSketch sketch = array.get(i);
			if (sketch == null || sketch.getRetainedEntries() == 0) {
				continue;
			}
			out.writeByte(recType);
			out.writeBoolean(isDelete);
			out.writeByte(fixed);
			out.writeByte(other);
			out.writeInt(i);
			writeSketch(out, sketch);
		}
	}

	private static void writePairBuild(DataOutputStream out, Pair pair, boolean isDelete, PairBuild build)
			throws IOException {
		if (build == null) {
			return;
		}
		for (Map.Entry<Integer, PairBuild.Row> entry : build.rows.entrySet()) {
			int x = entry.getKey();
			PairBuild.Row row = entry.getValue();
			if (row == null) {
				continue;
			}
			writePairRow(out, pair, isDelete, REC_PAIR_TRIPLE, row.triples, x);
			writePairRow(out, pair, isDelete, REC_PAIR_COMP1, row.comp1, x);
			writePairRow(out, pair, isDelete, REC_PAIR_COMP2, row.comp2, x);
		}
	}

	private static void writePairRow(DataOutputStream out, Pair pair, boolean isDelete, byte recType,
			Map<Integer, UpdateSketch> array, int x) throws IOException {
		for (Map.Entry<Integer, UpdateSketch> entry : array.entrySet()) {
			int y = entry.getKey();
			UpdateSketch sketch = entry.getValue();
			if (sketch == null || sketch.getRetainedEntries() == 0) {
				continue;
			}
			out.writeByte(recType);
			out.writeBoolean(isDelete);
			out.writeByte((byte) pair.ordinal());
			out.writeInt(x);
			out.writeInt(y);
			writeSketch(out, sketch);
		}
	}

	private static void readStateInto(DataInputStream in, State stateA, State stateB) throws IOException {
		while (true) {
			byte rec = in.readByte();
			if (rec == REC_EOF) {
				return;
			}

			switch (rec) {
			case REC_SINGLE_TRIPLE: {
				boolean isDelete = in.readBoolean();
				Component component = Component.values()[in.readByte()];
				int idx = in.readInt();
				UpdateSketch skA = readSketch(in, stateA.k);
				UpdateSketch skB = cloneSketch(skA, stateB.k);

				AtomicReferenceArray<UpdateSketch> arrA = isDelete ? stateA.delSingleTriples.get(component)
						: stateA.singleTriples.get(component);
				AtomicReferenceArray<UpdateSketch> arrB = isDelete ? stateB.delSingleTriples.get(component)
						: stateB.singleTriples.get(component);
				arrA.set(idx, skA);
				arrB.set(idx, skB);
				break;
			}
			case REC_SINGLE_CPL: {
				boolean isDelete = in.readBoolean();
				Component fixed = Component.values()[in.readByte()];
				Component other = Component.values()[in.readByte()];
				int idx = in.readInt();
				UpdateSketch skA = readSketch(in, stateA.k);
				UpdateSketch skB = cloneSketch(skA, stateB.k);

				SingleBuild sbA = isDelete ? stateA.delSingles.get(fixed) : stateA.singles.get(fixed);
				SingleBuild sbB = isDelete ? stateB.delSingles.get(fixed) : stateB.singles.get(fixed);
				sbA.cmpl.get(other).set(idx, skA);
				sbB.cmpl.get(other).set(idx, skB);
				break;
			}
			case REC_PAIR_TRIPLE:
			case REC_PAIR_COMP1:
			case REC_PAIR_COMP2: {
				boolean isDelete = in.readBoolean();
				Pair pair = Pair.values()[in.readByte()];
				int x = in.readInt();
				int y = in.readInt();
				UpdateSketch skA = readSketch(in, stateA.k);
				UpdateSketch skB = cloneSketch(skA, stateB.k);

				PairBuild pbA = isDelete ? stateA.delPairs.get(pair) : stateA.pairs.get(pair);
				PairBuild pbB = isDelete ? stateB.delPairs.get(pair) : stateB.pairs.get(pair);

				PairBuild.Row rowA = pbA.getOrCreateRow(x);
				PairBuild.Row rowB = pbB.getOrCreateRow(x);

				Map<Integer, UpdateSketch> arrA;
				Map<Integer, UpdateSketch> arrB;
				if (rec == REC_PAIR_TRIPLE) {
					arrA = rowA.triples;
					arrB = rowB.triples;
				} else if (rec == REC_PAIR_COMP1) {
					arrA = rowA.comp1;
					arrB = rowB.comp1;
				} else {
					arrA = rowA.comp2;
					arrB = rowB.comp2;
				}

				arrA.put(y, skA);
				arrB.put(y, skB);
				break;
			}
			default:
				throw new IOException("Unknown estimator snapshot record type: " + rec);
			}
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Array helpers (private) */
	/* ────────────────────────────────────────────────────────────── */

	private static void clearArray(AtomicReferenceArray<?> arr) {
		if (arr == null) {
			return;
		}
		for (int i = 0; i < arr.length(); i++) {
			arr.set(i, null);
		}
	}

	private static void updateCell(AtomicReferenceArray<UpdateSketch> arr, int idx, long value, int k) {
		UpdateSketch sk = arr.get(idx);
		if (sk == null) {
			sk = newSk(k);
			arr.set(idx, sk);
		}
		sk.update(value);
	}

	private static void updateSketchMap(Map<Integer, UpdateSketch> map, int idx, long value, int k) {
		UpdateSketch sk = map.get(idx);
		if (sk == null) {
			sk = newSk(k);
			map.put(idx, sk);
		}
		sk.update(value);
	}

